/*#
  MapSCII - Terminal Map Viewer
  by Michael Strassburger <codepoet@cpan.org>

  Patched by libwatchduty: upstream main.js ignored argv flags entirely
  (see TODO note in original). We honor MAPSCII_LAT / MAPSCII_LNG /
  MAPSCII_ZOOM env vars so the embedded host can open the map directly
  at the selected fire's coordinates.
#*/
'use strict';
const Mapscii = require('./src/Mapscii');
const config = require('./src/config');

function readFloatEnv(name) {
  const v = process.env[name];
  if (v === undefined || v === '') return null;
  const n = parseFloat(v);
  return Number.isFinite(n) ? n : null;
}

const lat = readFloatEnv('MAPSCII_LAT');
const lng = readFloatEnv('MAPSCII_LNG');
const zoom = readFloatEnv('MAPSCII_ZOOM');

// Make sure init() does NOT clobber our zoom with config.initialZoom.
if (zoom !== null) {
  config.initialZoom = zoom;
}

const mapscii = new Mapscii();

// Set center BEFORE init() so the first tile fetch targets the right area.
if (lat !== null && lng !== null) {
  mapscii.center = { lat: lat, lon: lng };
}

mapscii.init().then(() => {
  // Re-apply post-init in case init reset anything, then nudge several
  // redraws so the frame catches up after the tile fetch completes.
  if (lat !== null && lng !== null) {
    mapscii.setCenter(lat, lng);
  }
  if (zoom !== null) {
    mapscii.zoom = zoom;
  }
  if (typeof mapscii._draw === 'function') {
    mapscii._draw();
    setTimeout(() => mapscii._draw(), 150);
    setTimeout(() => mapscii._draw(), 600);
    setTimeout(() => mapscii._draw(), 1500);
  }
}).catch((err) => {
  console.error('Failed to start MapSCII.');
  console.error(err);
});
